// Read potentiometer value and control LED brightness
const int potPin = A0;    // Potentiometer on analog pin 0
const int ledPin = 9;     // LED on PWM pin 9

void setup() {
  pinMode(ledPin, OUTPUT);
  Serial.begin(9600);
}

void loop() {
  // Read potentiometer (0-1023)
  int potValue = analogRead(potPin);

  // Map to PWM range (0-255)
  int brightness = map(potValue, 0, 1023, 0, 255);

  // Set LED brightness
  analogWrite(ledPin, brightness);

  // Display values
  Serial.print("Pot: ");
  Serial.print(potValue);
  Serial.print(" | Brightness: ");
  Serial.println(brightness);

  delay(100);
}

// Drive a 5V relay using 2N2222 transistor
// Safe switching with flyback protection

const int relayPin = 7;  // Digital pin controlling transistor base

void setup() {
  pinMode(relayPin, OUTPUT);
  Serial.begin(9600);
}

void loop() {
  // Turn relay ON
  digitalWrite(relayPin, HIGH);
  Serial.println("Relay ON");
  delay(2000);

  // Turn relay OFF
  digitalWrite(relayPin, LOW);
  Serial.println("Relay OFF");
  delay(2000);
}

/* Circuit Connection:
   Arduino Pin 7 ──[1kΩ]── Base (Pin 2) of 2N2222
   Collector (Pin 3) ── Relay Coil + ── 5V
   Emitter (Pin 1) ── GND

   Flyback Protection:
   1N4007 diode across relay coil (cathode to +5V)

   Base Resistor Calculation:
   Rb = (Vcc - Vbe) / Ib
   Ib = Ic / hFE
   For relay current ~50mA, hFE=100:
   Ib = 50mA / 100 = 0.5mA
   Rb = (5V - 0.7V) / 0.5mA = 8.6kΩ
   Use standard 10kΩ for saturation (~0.43mA base current)
*/

// Control DC motor speed using IRF540N MOSFET
// PWM signal from Arduino drives MOSFET gate

const int motorPin = 9;      // PWM pin connected to MOSFET gate
const int potPin = A0;       // Potentiometer for speed control

void setup() {
  pinMode(motorPin, OUTPUT);
  Serial.begin(9600);
}

void loop() {
  // Read potentiometer (0-1023)
  int potValue = analogRead(potPin);

  // Map to PWM range (0-255)
  int motorSpeed = map(potValue, 0, 1023, 0, 255);

  // Set motor speed via PWM
  analogWrite(motorPin, motorSpeed);

  // Display speed percentage
  int speedPercent = map(motorSpeed, 0, 255, 0, 100);
  Serial.print("Motor Speed: ");
  Serial.print(speedPercent);
  Serial.println("%");

  delay(50);
}

/* Circuit Connections:

   Arduino Pin 9 (PWM) ──[220Ω]── Gate (Pin 1)

   Motor + ── Battery +
   Motor - ── Drain (Pin 2)
   Source (Pin 3) ── GND (common with Arduino GND)

   Flyback Diode:
   1N4007 across motor (cathode to Motor+)

   Gate Resistor:
   220Ω-1kΩ between Arduino and Gate
   (limits current, prevents gate oscillation)

   Pull-down:
   10kΩ resistor from Gate to Source
   (ensures MOSFET is OFF when Arduino pin is floating)
*/

// Control 8 LEDs using only 3 Arduino pins
// Uses 74HC595 shift register

const int dataPin = 8;   // DS  - Serial data
const int latchPin = 9;  // STCP - Latch/storage clock
const int clockPin = 10; // SHCP - Shift clock

void setup() {
  pinMode(dataPin, OUTPUT);
  pinMode(latchPin, OUTPUT);
  pinMode(clockPin, OUTPUT);
}

void loop() {
 //Running LED animation
  for (int i = 0; i < 8; i++) {
    byte pattern = 1 << i;  // Shift bit left: 00000001, 00000010, 00000100...
    updateShiftRegister(pattern);
    delay(100);
  }

  // All LEDs blink
  updateShiftRegister(0xFF);  // All ON (11111111)
  delay(500);
  updateShiftRegister(0x00);  // All OFF (00000000)
  delay(500);
}

void updateShiftRegister(byte data) {
  // Pull latch LOW to start sending data
  digitalWrite(latchPin, LOW);

  // Send 8 bits of data
  shiftOut(dataPin, clockPin, MSBFIRST, data);

  // Pull latch HIGH to update outputs
  digitalWrite(latchPin, HIGH);
}

/* Circuit Connections:
   Arduino Pin 8 (dataPin) ──── Pin 14 (DS)
   Arduino Pin 9 (latchPin) ─── Pin 12 (STCP)
   Arduino Pin 10 (clockPin) ── Pin 11 (SHCP)

   Pin 10 (MR) ── Vcc (master reset disabled)
   Pin 13 (OE) ── GND (output always enabled)
   Pin 16 (Vcc) ── +5V
   Pin 8 (GND) ── GND

   Outputs (Q0-Q7) ──[330Ω]── LED ──── GND

   Cascading (for 16+ LEDs):
   Pin 9 (Q7S) of first IC ── Pin 14 (DS) of second IC
   Share clock and latch pins between ICs
*/

// Control 2 DC motors with L293D
// Speed and direction control for robot car

// Motor A connections
const int enA = 9;   // Enable/PWM for Motor A
const int in1 = 8;   // Direction control 1
const int in2 = 7;   // Direction control 2

// Motor B connections  
const int enB = 3;   // Enable/PWM for Motor B
const int in3 = 5;   // Direction control 3
const int in4 = 4;   // Direction control 4

void setup() {
  pinMode(enA, OUTPUT);
  pinMode(in1, OUTPUT);
  pinMode(in2, OUTPUT);
  pinMode(enB, OUTPUT);
  pinMode(in3, OUTPUT);
  pinMode(in4, OUTPUT);
}

void loop() {
  moveForward(200);    // Forward at speed 200/255
  delay(2000);

  moveBackward(150);   // Backward at speed 150/255
  delay(2000);

  turnRight(180);      // Turn right
  delay(1000);

  stopMotors();        // Stop
  delay(1000);
}

void moveForward(int speed) {
  // Motor A forward
  digitalWrite(in1, HIGH);
  digitalWrite(in2, LOW);
  analogWrite(enA, speed);

  // Motor B forward
  digitalWrite(in3, HIGH);
  digitalWrite(in4, LOW);
  analogWrite(enB, speed);
}

void moveBackward(int speed) {
  digitalWrite(in1, LOW);
  digitalWrite(in2, HIGH);
  analogWrite(enA, speed);

  digitalWrite(in3, LOW);
  digitalWrite(in4, HIGH);
  analogWrite(enB, speed);
}

void turnRight(int speed) {
  // Motor A forward, Motor B backward
  digitalWrite(in1, HIGH);
  digitalWrite(in2, LOW);
  digitalWrite(in3, LOW);
  digitalWrite(in4, HIGH);
  analogWrite(enA, speed);
  analogWrite(enB, speed);
}

void stopMotors() {
  analogWrite(enA, 0);
  analogWrite(enB, 0);
}

/* Pin Connections:
   Arduino → L293D:
   Pin 9 (PWM) → Pin 1 (EN1)
   Pin 8 → Pin 2 (IN1)
   Pin 7 → Pin 7 (IN2)
   Motor A → Pins 3 & 6 (OUT1, OUT2)

   Pin 3 (PWM) → Pin 9 (EN2)
   Pin 5 → Pin 10 (IN3)
   Pin 4 → Pin 15 (IN4)
   Motor B → Pins 11 & 14 (OUT3, OUT4)

   +5V → Pin 16 (Vcc1)
   Motor Power (+6-12V) → Pin 8 (Vcc2)
   GND → Pins 4, 5, 12, 13 (all grounds)
*/

// Basic LED blink with current limiting resistor
const int ledPin = 13;

void setup() {
  pinMode(ledPin, OUTPUT);
}

void loop() {
  digitalWrite(ledPin, HIGH);  // LED ON
  delay(1000);
  digitalWrite(ledPin, LOW);   // LED OFF
  delay(1000);
}

/* Resistor Calculation:
   Ohm's Law: R = V / I

   For Red LED with Arduino (5V):
   - Supply Voltage (Vs) = 5V
   - LED Forward Voltage (Vf) = 2V
   - Desired Current (If) = 20mA = 0.02A

   Voltage across resistor = Vs - Vf = 5V - 2V = 3V
   Resistance = V / I = 3V / 0.02A = 150Ω

   Use 150Ω or 220Ω (next standard value)

   For other colors:
   - Green/Yellow LED (Vf ≈ 2.2V): Use 150Ω-220Ω
   - Blue/White LED (Vf ≈ 3.3V): Use 100Ω-150Ω

   Circuit:
   Arduino Pin → [Resistor] → LED Anode (+) → LED Cathode (-) → GND
*/

// Requires Adafruit BMP280 library
#include <Wire.h>
#include <Adafruit_BMP280.h>

Adafruit_BMP280 bmp; // I2C

void setup() {
  Serial.begin(9600);

  if (!bmp.begin(0x76)) {
    Serial.println("BMP280 not found!");
    while (1);
  }

  // Default settings
  bmp.setSampling(Adafruit_BMP280::MODE_NORMAL,
                  Adafruit_BMP280::SAMPLING_X2,
                  Adafruit_BMP280::SAMPLING_X16,
                  Adafruit_BMP280::FILTER_X16,
                  Adafruit_BMP280::STANDBY_MS_500);
}

void loop() {
  float temp = bmp.readTemperature();
  float pressure = bmp.readPressure() / 100.0F;
  float altitude = bmp.readAltitude(1013.25);

  Serial.print("Temperature: ");
  Serial.print(temp);
  Serial.println(" °C");

  Serial.print("Pressure: ");
  Serial.print(pressure);
  Serial.println(" hPa");

  Serial.print("Altitude: ");
  Serial.print(altitude);
  Serial.println(" m");
  Serial.println();

  delay(2000);
}

// Requires MPU6050 library
#include <Wire.h>
#include <MPU6050.h>

MPU6050 mpu;

void setup() {
  Serial.begin(115200);
  Wire.begin();

  mpu.initialize();

  if (!mpu.testConnection()) {
    Serial.println("MPU6050 connection failed");
    while(1);
  }

  Serial.println("MPU6050 ready!");
}

void loop() {
  int16_t ax, ay, az;
  mpu.getAcceleration(&ax, &ay, &az);

  int16_t gx, gy, gz;
  mpu.getRotation(&gx, &gy, &gz);

  Serial.print("Accel X:"); Serial.print(ax);
  Serial.print(" Y:"); Serial.print(ay);
  Serial.print(" Z:"); Serial.println(az);

  Serial.print("Gyro X:"); Serial.print(gx);
  Serial.print(" Y:"); Serial.print(gy);
  Serial.print(" Z:"); Serial.println(gz);
  Serial.println();

  delay(500);
}

// Requires MFRC522 library
#include <SPI.h>
#include <MFRC522.h>

#define SS_PIN 10
#define RST_PIN 9

MFRC522 rfid(SS_PIN, RST_PIN);

void setup() {
  Serial.begin(9600);
  SPI.begin();
  rfid.PCD_Init();

  Serial.println("RFID Reader Ready");
  Serial.println("Place card near reader...");
}

void loop() {
  if (!rfid.PICC_IsNewCardPresent())
    return;

  if (!rfid.PICC_ReadCardSerial())
    return;

  Serial.print("Card UID: ");
  for (byte i = 0; i < rfid.uid.size; i++) {
    Serial.print(rfid.uid.uidByte[i] < 0x10 ? " 0" : " ");
    Serial.print(rfid.uid.uidByte[i], HEX);
  }
  Serial.println();

  rfid.PICC_HaltA();
  rfid.PCD_StopCrypto1();

  delay(1000);
}

// Requires Adafruit PN532 library
#include <Wire.h>
#include <Adafruit_PN532.h>

Adafruit_PN532 nfc(2, 3);

void setup() {
  Serial.begin(115200);
  nfc.begin();

  uint32_t versiondata = nfc.getFirmwareVersion();
  if (!versiondata) {
    Serial.println("PN532 not found!");
    while (1);
  }

  Serial.print("Found PN53");
  Serial.println((versiondata >> 24) & 0xFF, HEX);

  nfc.SAMConfig();
  Serial.println("Waiting for NFC card...");
}

void loop() {
  uint8_t uid[] = {0, 0, 0, 0, 0, 0, 0};
  uint8_t uidLength;

  if (nfc.readPassiveTargetID(PN532_MIFARE_ISO14443A, uid, &uidLength)) {
    Serial.print("Found card with UID: ");
    for (uint8_t i = 0; i < uidLength; i++) {
      Serial.print(" 0x");
      Serial.print(uid[i], HEX);
    }
    Serial.println();

    delay(1000);
  }
}

